import { BrowserRouter as useNavigate } from 'react-router-dom';

function HomeButton() {
    const navigate = useNavigate();
  
    return (
      <div>
        <CustomButton
          buttonLabel={"home"}
          onClick={() => navigate('/')}
        />
      </div>
    );
  }

  function Game(){
    
    return <>
    <CustomGameCard
      gameTitle={"Sediento"}
      gameEmbed={"./Sediento/game.html"}
      buttonText={"Clicka!"}
      maxWidth={600}
    />
    <HomeButton/>
    </>
  }

  export default Game;
